import { getDataByKeys } from './data-by-keys';
import { d3_extent } from '../../core/d3-constants';

/**
 * @param  {Array} array
 * @param  {[Array | Number | String]} keys
 * @return {Array}       [min, max]
 */
export function extent(array, keys) {
    var data = getDataByKeys(array, keys);
    return d3_extent(data);
}
